using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9: ZipArchiveEntry now sets the UTF-8 flag, which would cause
        // the legacy Java consumer (Shift-JIS) to misread non-ASCII filenames.
        // Specify Shift-JIS encoding explicitly so the UTF-8 flag is NOT set
        // and entry names are written in the encoding the consumer expects.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9: [FromKeyedServices] no longer falls back to non-keyed services.
// Register as a keyed service to match the controller's attribute.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

